import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaSave, FaTimes, FaBriefcase, FaBuilding, FaCalendar, FaStickyNote } from 'react-icons/fa';
import { FaLink } from 'react-icons/fa';
import { useJobs } from '../context/JobContext';
function AddJob() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    company: '',
    position: '',
    link: '',
    status: 'Applied',
    date: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const [errors, setErrors] = useState({});

  const statusOptions = ['Applied', 'Interviewing', 'Offer', 'Rejected'];
  const { addJob } = useJobs();

  const validateForm = () => {
    const newErrors = {};
    if (!formData.company.trim()) newErrors.company = 'Company name is required';
    if (!formData.position.trim()) newErrors.position = 'Position is required';
    if (!formData.date) newErrors.date = 'Date is required';
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear error for this field when user starts typing
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: null
      }));
    }
  };

  const handleSubmit = (e) => {
  e.preventDefault();
  
  if (validateForm()) {
    addJob(formData);
    navigate('/');
  }
};

  const handleCancel = () => {
    navigate('/');
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4 max-w-3xl">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-800 mb-2">Add New Application</h1>
          <p className="text-gray-600">Fill in the details of your job application</p>
        </div>

        {/* Form Card */}
        <div className="bg-white rounded-lg shadow-lg overflow-hidden">
          <form onSubmit={handleSubmit} className="p-6 space-y-6">
            {/* Company Name */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <FaBuilding className="inline mr-2 text-purple-600" />
                Company Name *
              </label>
              <input
                type="text"
                name="company"
                value={formData.company}
                onChange={handleChange}
                placeholder="e.g., Google, Microsoft, Amazon"
                className={`w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 ${
                  errors.company ? 'border-red-500' : 'border-gray-300'
                }`}
              />
              {errors.company && (
                <p className="mt-1 text-sm text-red-600">{errors.company}</p>
              )}
            </div>

            {/* Position */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <FaBriefcase className="inline mr-2 text-purple-600" />
                Position *
              </label>
              <input
                type="text"
                name="position"
                value={formData.position}
                onChange={handleChange}
                placeholder="e.g., Frontend Developer, UI Designer"
                className={`w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 ${
                  errors.position ? 'border-red-500' : 'border-gray-300'
                }`}
              />
              {errors.position && (
                <p className="mt-1 text-sm text-red-600">{errors.position}</p>
              )}
            </div>
            <div>
  <label className="block text-sm font-medium text-gray-700 mb-2">
    <FaLink className="inline mr-2 text-purple-600" />
    Job Posting Link
  </label>
  <input
    type="url"
    name="link"
    value={formData.link}
    onChange={handleChange}
    placeholder="https://www.linkedin.com/jobs/... or company career page"
    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
  />
  <p className="mt-1 text-xs text-gray-500">
    Add link to job posting for quick access later
  </p>
</div>
            {/* Status and Date - Grid Layout */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Status Dropdown */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Status
                </label>
                <select
                  name="status"
                  value={formData.status}
                  onChange={handleChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                >
                  {statusOptions.map(status => (
                    <option key={status} value={status}>{status}</option>
                  ))}
                </select>
              </div>

              {/* Date Picker */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  <FaCalendar className="inline mr-2 text-purple-600" />
                  Application Date *
                </label>
                <input
                  type="date"
                  name="date"
                  value={formData.date}
                  onChange={handleChange}
                  className={`w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 ${
                    errors.date ? 'border-red-500' : 'border-gray-300'
                  }`}
                />
                {errors.date && (
                  <p className="mt-1 text-sm text-red-600">{errors.date}</p>
                )}
              </div>
            </div>

            {/* Notes */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <FaStickyNote className="inline mr-2 text-purple-600" />
                Notes
              </label>
              <textarea
                name="notes"
                value={formData.notes}
                onChange={handleChange}
                rows="4"
                placeholder="Add any notes about your application (job description, contact person, interview details, etc.)"
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
              />
            </div>

            {/* Form Tips */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <h4 className="text-sm font-semibold text-blue-800 mb-2">✨ Pro Tips:</h4>
              <ul className="text-sm text-blue-700 space-y-1">
                <li>• Add the company website or job posting link</li>
                <li>• Include contact person details if you have them</li>
                <li>• Note down interview dates and follow-up reminders</li>
              </ul>
            </div>

            {/* Action Buttons */}
            <div className="flex justify-end gap-4 pt-4 border-t border-gray-200">
              <button
                type="button"
                onClick={handleCancel}
                className="px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition flex items-center gap-2"
              >
                <FaTimes />
                Cancel
              </button>
              <button
                type="submit"
                className="px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition flex items-center gap-2"
              >
                <FaSave />
                Save Application
              </button>
            </div>
          </form>
        </div>

        {/* Preview Card */}
{formData.company && formData.position && (
  <div className="mt-8">
    <h3 className="text-lg font-semibold text-gray-700 mb-4">Preview:</h3>
    <div className="bg-purple-50 border border-purple-200 rounded-lg p-4">
      <div className="flex justify-between items-start">
        <div>
          <p className="text-sm text-purple-800">
            <span className="font-bold">{formData.company}</span> - {formData.position}
            <span className="ml-2 px-2 py-1 bg-purple-200 rounded-full text-xs">
              {formData.status}
            </span>
          </p>
          <p className="text-xs text-purple-600 mt-2">
            Applied on: {new Date(formData.date).toLocaleDateString()}
          </p>
          {formData.link && (
            <p className="text-xs text-purple-600 mt-1 truncate max-w-md">
              <FaLink className="inline mr-1" />
              <a href={formData.link} target="_blank" rel="noopener noreferrer" 
                 className="hover:underline">
                {formData.link}
              </a>
            </p>
          )}
        </div>
      </div>
    </div>
  </div>
)}
      </div>
    </div>
  );
}

export default AddJob;
